const raw = $input.first().json;
const event = raw.event || raw.body?.event || 'no-event';
const data = raw.data || raw.body?.data || {};
const msgText = data.message?.conversation || data.message?.extendedTextMessage?.text || '';
const t = msgText.toLowerCase().trim();
const original = msgText.trim();
if (event !== 'messages.upsert') return [{ json: { reply: 'skip', phoneNumber: '14432576836@s.whatsapp.net', skip: true } }];
if (t.includes('bot reply:')) return [{ json: { reply: 'skip', phoneNumber: '14432576836@s.whatsapp.net', skip: true } }];
const from = data.key?.remoteJid || data.remoteJid || '14432576836@s.whatsapp.net';
const feedbackPatterns = [/^(y|yes|good|correct|accurate|useful|approved)\b/i, /^(n|no|wrong|incorrect|bad|useless|skip|ignore|reject)\b/i, /^feedback[:\s]/i];
const isFeedback = feedbackPatterns.some(p => p.test(t));
if (isFeedback) {
  const SUPABASE_URL = ($env.SUPABASE_URL || '').replace('https://','').replace('http://','');
  const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY;
  let decision = 'noted';
  if (/^(y|yes|good|correct|accurate|useful|approved)\b/i.test(t)) decision = 'approved';
  if (/^(n|no|wrong|incorrect|bad|useless|skip|ignore|reject)\b/i.test(t)) decision = 'rejected';
  const noteMatch = original.match(/^\S+\s+(.*)$/s);
  const note = noteMatch ? noteMatch[1].trim() : '';
  const https = require('https');
  const supabaseGet = (path) => new Promise((resolve, reject) => {
    const opts = { hostname: SUPABASE_URL, port: 443, path: '/rest/v1/' + path, method: 'GET', headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY } };
    let b = ''; const req = https.request(opts, res => { res.on('data', c => b += c); res.on('end', () => { try { resolve(JSON.parse(b || '[]')); } catch(e) { resolve([]); } }); }); req.on('error', reject); req.end();
  });
  const supabasePost = (table, payload) => new Promise((resolve, reject) => {
    const bodyStr = JSON.stringify(payload);
    const opts = { hostname: SUPABASE_URL, port: 443, path: '/rest/v1/' + table, method: 'POST', headers: { 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Content-Type': 'application/json', 'Prefer': 'return=minimal', 'Content-Length': Buffer.byteLength(bodyStr) } };
    const req = https.request(opts, res => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve({ status: res.statusCode })); }); req.on('error', reject); req.write(bodyStr); req.end();
  });
  let lastAgent = 'unknown'; let lastExecId = null;
  try { const execs = await supabaseGet('agent_executions?select=id,agent&order=created_at.desc&limit=1'); if (execs[0]) { lastAgent = execs[0].agent; lastExecId = execs[0].id; } } catch(e) {}
  let writeStatus = 'unknown';
  try { const r = await supabasePost('agent_feedback', { agent: lastAgent, action_type: 'whatsapp_feedback', reference_id: lastExecId, reference_table: 'agent_executions', kevin_decision: decision, notes: note || null, content_type: 'execution_output' }); writeStatus = r.status === 201 ? 'saved' : 'error_' + r.status; } catch(e) { writeStatus = 'error: ' + e.message; }
  return [{ json: { reply: 'Bot reply: \u2713 Feedback recorded\nAgent: ' + lastAgent + '\nDecision: ' + decision + (note ? '\nNote: ' + note : '') + '\nStatus: ' + writeStatus, phoneNumber: from, skip: false } }];
}
const agents = ['aidan','jordan','scout','iris','atlas','nova','sage','pulse','orchestra'];
if (!t || !agents.some(a => t.startsWith(a))) return [{ json: { reply: 'skip', phoneNumber: '14432576836@s.whatsapp.net', skip: true } }];
let reply = '';
const http = require('http');
const fireWebhook = async (path, payload) => {
  const bodyStr = JSON.stringify(payload);
  const opts = { hostname: 'host.docker.internal', port: 5678, path, method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(bodyStr) } };
  await new Promise(r => { const req = http.request(opts, res => { res.on('data',()=>{}); res.on('end',r); }); req.on('error',r); req.write(bodyStr); req.end(); });
};
if (t.startsWith('orchestra')) {
  const query = t.replace(/^orchestra[,\s]*/i,'').trim() || 'Full platform status';
  await fireWebhook('/webhook/aidan-orchestra', { query, from });
  reply = 'Bot reply: \uD83C\uDFBC ORCHESTRA INITIATED\nFiring: Atlas + Scout + Jordan + Iris\nQuery: ' + query.substring(0,80) + '\n\nConsolidated brief incoming ~90 seconds.';
} else if (t.startsWith('aidan')) {
  const cmd = t.replace(/^aidan[,\s]*/i,'').trim();
  if (cmd === 'help' || cmd === '?') {
    reply = 'Bot reply: AIDAN v4 Commands\n\nIntelligence:\n- Nova scan -- full proactive sweep\n- Nova scan [topic] -- focused sweep\n- Nova pursue [opportunity] -- add to pipeline + Jordan drafts\n- Scout [target] -- BD research\n- Scout pursue [opportunity] -- FP contract pipeline\n\nAgents:\n- Atlas [query]\n- Jordan grant\n- Iris deadlines\n- Sage board | Sage market\n- Pulse\n- Orchestra [query] -- fires ALL agents\n\nFeedback:\n- Y [note] -- mark useful\n- N [note] -- mark wrong\n\nBriefings:\n- Aidan brief | Aidan status';
  } else if (cmd.includes('brief') || cmd.includes('status') || cmd.includes('morning')) {
    reply = 'Bot reply: ' + new Date().toLocaleString('en-US',{timeZone:'America/New_York'}) + ' EST\nAidan v4 online. Feedback: ACTIVE \u2705\nNova Proactive v3: ACTIVE \u2705\nPipeline: ACTIVE \u2705\nOrchestra ready.';
  } else { reply = 'Bot reply: Aidan received: ' + cmd + '\nSay Aidan help for full command menu.'; }
} else if (t.startsWith('jordan')) {
  const cmd = t.replace(/^jordan[,\s]*/i,'').trim();
  if (cmd.includes('grant detail') || cmd.includes('grant report')) {
    const fs = require('fs');
    try {
      const files = fs.readdirSync('/data/Aidan_Outputs/Jordan/').filter(f=>f.startsWith('Grant_Report')).sort().reverse();
      if (files.length > 0) { const rpt = fs.readFileSync('/data/Aidan_Outputs/Jordan/' + files[0], 'utf8'); reply = 'Bot reply: ' + rpt.substring(0,3500); }
      else reply = 'Bot reply: No grant reports found.';
    } catch(e) { reply = 'Bot reply: Error: ' + e.message; }
  } else { await fireWebhook('/webhook/grant-writer', { trigger: 'whatsapp', from }); reply = 'Bot reply: Jordan running. Report ready ~45 seconds.'; }
} else if (t.startsWith('nova') || t.startsWith('scout')) {
  const agent = t.startsWith('nova') ? 'nova' : 'scout';
  const cmd = t.replace(new RegExp('^' + agent + '[,\\s]*','i'),'').trim();
  if (cmd.startsWith('pursue')) {
    const opportunity = cmd.replace(/^pursue[,\s]*/i,'').trim();
    if (!opportunity) {
      reply = 'Bot reply: Pursue what? Try:\nNova pursue FEMA preparedness grant\nScout pursue BGE utility inspection';
    } else {
      const parts = opportunity.split(' -- ');
      const title = parts[0].trim();
      const note = parts[1] ? parts[1].trim() : '';
      const entityHint = agent === 'scout' ? 'FP' : '';
      await fireWebhook('/webhook/nova-pursue', { title, note, source: agent, entity: entityHint });
      reply = 'Bot reply: Pipeline initiated.\nOpportunity: ' + title.substring(0,80) + '\nJordan drafting. Pipeline record being created.\nConfirmation incoming ~30 seconds.';
    }
  } else if (agent === 'nova') {
    if (cmd === 'scan' || cmd === 'proactive' || cmd === '') {
      await fireWebhook('/webhook/nova-proactive', { source: 'whatsapp' });
      reply = 'Bot reply: Nova Proactive v3 running.\nUSASpending + SAM + SBIR + Grants + Regulations + Brave.\nDeriving regulatory and business targets from KAI_Context.\nTier 1 brief incoming ~2 minutes.';
    } else if (cmd.startsWith('scan ') || cmd.startsWith('focus ')) {
      const focus = cmd.replace(/^(scan|focus)\s*/i,'').trim();
      await fireWebhook('/webhook/nova-proactive', { focus: focus, source: 'whatsapp' });
      reply = 'Bot reply: Nova Proactive focused sweep: ' + focus.substring(0,60) + '\nBrief incoming ~2 minutes.';
    } else {
      await fireWebhook('/webhook/nova-rfp', { rfp_text: cmd, rfp_name: 'WhatsApp RFP', agency: 'Unknown', source: 'whatsapp' });
      reply = 'Bot reply: Nova RFP analysis running.\nReport ready ~45 seconds.';
    }
  } else {
    const query = cmd || 'Maryland drone infrastructure inspection contracts 2026';
    await fireWebhook('/webhook/scout-research', { query });
    reply = 'Bot reply: Scout running: ' + query.substring(0,60) + '\nReport ready ~60 seconds.';
  }
} else if (t.startsWith('iris')) {
  await fireWebhook('/webhook/iris-monitor', { trigger: 'whatsapp', from });
  reply = 'Bot reply: Iris running... ~15 seconds.';
} else if (t.startsWith('atlas')) {
  const cmd = t.replace(/^atlas[,\s]*/i,'').trim();
  const validCmds = ['sbir','meia','monk','bvlos','kott prep','status','v1','v2','v3','v4','v5','v6','v7'];
  const matched = validCmds.find(c => cmd.toLowerCase().startsWith(c));
  const atlasCmd = 'Atlas ' + (matched ? matched.toUpperCase() : cmd || 'status');
  await fireWebhook('/webhook/atlas-architect', { command: atlasCmd, detail: cmd });
  reply = 'Bot reply: Atlas running: ' + atlasCmd + '\nReport ready ~45 seconds.';
} else if (t.startsWith('sage')) {
  const cmd = t.replace(/^sage[,\s]*/i,'').trim();
  if (cmd === 'send board') {
    await fireWebhook('/webhook/sage-send', { newsletter: 'board', from });
    reply = 'Bot reply: Sage sending EAF Board newsletter.';
  } else if (cmd === 'send market') {
    await fireWebhook('/webhook/sage-send', { newsletter: 'market', from });
    reply = 'Bot reply: Sage sending FP Market newsletter.';
  } else {
    await fireWebhook('/webhook/sage-newsletter', { trigger: cmd || 'board', from });
    reply = 'Bot reply: Sage Newsletter running. Draft ready ~45 seconds.';
  }
} else if (t.startsWith('pulse')) {
  await fireWebhook('/webhook/pulse-metrics', { trigger: 'whatsapp', from });
  reply = 'Bot reply: Pulse running platform health check. Report ready ~30 seconds.';
} else {
  const name = t.split(/\s/)[0];
  reply = 'Bot reply: ' + name.charAt(0).toUpperCase()+name.slice(1) + ' — say Orchestra to fire all, or Aidan help for menu.';
}
return [{ json: { reply, phoneNumber: from, skip: false } }];

const input = $input.first().json;
if (input.skip || !input.reply || input.reply === 'skip') return [{ json: { success: true, skipped: true } }];
const number = (input.phoneNumber || '14432576836@s.whatsapp.net').includes('@lid') ? '14432576836@s.whatsapp.net' : (input.phoneNumber || '14432576836@s.whatsapp.net');
const body = JSON.stringify({ number, textMessage: { text: input.reply } });
const opts = { hostname: 'host.docker.internal', port: 8081, path: '/message/sendText/Aidan', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(body) } };
const result = await new Promise((resolve, reject) => {
  const http = require('http');
  const req = http.request(opts, res => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve({ status: res.statusCode })); });
  req.on('error', reject); req.write(body); req.end();
});
return [{ json: { success: true, result } }];
